// NODO: Ecom_Data_Formatter
// VERSIONE: 2.6 - Added Inventory Support & Full Operations Mapping

const item = $input.first().json;
const setupData = item.catalog_setup || {};
const itemNodes = item.catalog_item || [];
const honeyPotData = item.HoneyPot || {};
const ownerData = item.owner_data || {};

// --- CONTROLLO PAGAMENTI ---
const isPaymentActive = !!(ownerData.payment_provider_token && String(ownerData.payment_provider_token).trim() !== "");

// 1. Risoluzione dinamica ROOT immagini
const rawAppUrl = item.urlMiniApp || "";
const rootUrl = rawAppUrl.split('telegram_control/')[0];

// 2. Mappatura Catalog Items (Dettagli Tecnici)
const productSheets = {};
if (Array.isArray(itemNodes)) {
    itemNodes.forEach(wrapper => {
        const product = wrapper.catalog || wrapper.catalog_item_draft;
        if (product && product.identity) {
            const sku = product.ui_node_draft?.callback_data || product.identity.item_sku;

            productSheets[sku] = {
                full_name: product.identity.item_name || "",
                short_desc: product.identity.description?.short || "",
                long_desc: product.identity.description?.long || "",
                price: parseFloat(product.pricing?.base_price || 0),
                pricing: product.pricing || {},
                commercial_setup: product.commercial_setup || { extra_options: [], allow_customer_notes: false },
                // AGGIUNTO: Gestione Inventario
                inventory_enabled: product.operations?.requires_inventory_check || false,
                fulfillment_time: product.operations?.fulfillment_time || {}
            };
        }
    });
}

// 3. Recupero resiliente dello storico ordini
let historyData = [];
if (Array.isArray(item.order)) {
    historyData = item.order
        .map(entry => entry.order)
        .filter(o => o !== undefined && o !== null);
}

// 4. Incrocio Tassonomia con Filtri di Attivazione
const products = [];
if (setupData.categories) {
    setupData.categories.forEach(cat => {
        if (cat.macrocategories === "PRO" || cat.macrocategories === "SER") {
            cat.subcategories.forEach(sub => {
                // Filtro FONDAMENTALE: Passano solo i prodotti con blueprint attivo
                if (sub.blueprint_ready === true) {
                    const sheet = productSheets[sub.callback_data] || {};
                    products.push({
                        name: sheet.full_name || sub.name,
                        short_name: sub.short_name,
                        callback_data: sub.callback_data,
                        price: sheet.price || 0,
                        category: cat.name,
                        description: sheet.short_desc || "",
                        long_description: sheet.long_desc || "",
                        pricing: sheet.pricing || {},
                        commercial_setup: sheet.commercial_setup || {},
                        inventory_enabled: sheet.inventory_enabled || false,
                        fulfillment: sheet.fulfillment_time || {}
                    });
                }
            });
        }
    });
}

return [{
    json: {
        success: true,
        payment_active: false, //isPaymentActive (mantenuto come da tua versione)
        catalog: products,
        history: historyData,
        brand: {
            name: ownerData.ragione_sociale || "SiteBoS Store",
            logo: honeyPotData.assets?.logo?.url || ""
        },
        urlMiniApp: rootUrl,
        vat: ownerData.vat_number || ""
    }
}];

/**
 * NODO: Prepare_Order_Message
 * OBIETTIVO: Formattazione ordine con GPS Disclaimer e ricerca per indirizzo
 * VERSION: 1.7 - Full HORECA Security
 */
const item = $input.first().json;
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const orderData = item.body.order_data;
const owner = item.owner_data;
const customer = item.stakeholder || {};

// 1. Generazione ASH FIRMATO
function generateAsh(ownerId, customerId, timestamp, whId, secret) {
    const payload = `${ownerId}|${customerId}|${timestamp}|${whId}`;
    const encodedPayload = Buffer.from(payload, "utf8").toString("base64").replace(/=/g, '');
    let hash = 0;
    const combined = payload + secret;
    for (let i = 0; i < combined.length; i++) {
        hash = ((hash << 5) - hash) + combined.charCodeAt(i);
        hash = hash & hash; 
    }
    const signature = Math.abs(hash).toString(16);
    return `${encodedPayload}.${signature}`;
}

const ids = orderData.ids;
const ash = generateAsh(owner.chat_id, ids.customer_id, ids.timestamp, ids.webhook, SECRET_KEY);

// 2. Mappatura Dati Stakeholder
const userRef = customer.user_ref || {};
let customerDetails = "";
const schemaMap = [
    { key: "nome", label: "Nome" }, { key: "cognome", label: "Cognome" },
    { key: "email", label: "E-mail" }, { key: "telefono", label: "Telefono" },
    { key: "indirizzo", label: "Domicilio" }, { key: "comune", label: "Comune" }, 
    { key: "provincia", label: "Prov." }, { key: "cap", label: "Cap" }
];
schemaMap.forEach(f => { if (userRef[f.key]) customerDetails += `• ${f.label}: <code>${userRef[f.key]}</code>\n`; });

// 3. Costruzione Messaggio HTML
let msg = `<b>📦 NUOVO ORDINE RICEVUTO</b>\n`;
msg += `<code>ID: ${orderData.sessionId}</code>\n\n`;
msg += `👤 <b>PROFILO CLIENTE:</b>\n${customerDetails}\n`;

msg += `🚚 <b>DESTINAZIONE ORDINE:</b>\n`;
msg += `📍 Indirizzo: <code>${orderData.address}</code>\n`;

if (orderData.location?.display_name) {
    msg += `🌐 Rilevamento GPS: <i>${orderData.location.display_name}</i>\n`;
    msg += `⚠️ <i>Nota: La posizione rilevata potrebbe non essere precisa.</i>\n`;
}

// Link Maps basato sull'indirizzo testuale di consegna
const mapsSearchUrl = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(orderData.address)}`;
msg += `🗺 <a href="${mapsSearchUrl}">Calcola Percorso (Maps)</a>\n`;

msg += `\n💳 <b>PAGAMENTO:</b> ${orderData.payment_mode === 'CARD' ? '💳 CARTA' : '🚚 CONSEGNA'}\n\n`;

msg += `🛒 <b>DETTAGLIO ORDINE:</b>\n`;
orderData.items.forEach(i => {
    msg += `• <b>${i.quantity}x ${i.name}</b>\n`;
    if (i.selected_extras?.length > 0) i.selected_extras.forEach(e => msg += `  └ <i>+ ${e.name}</i>\n`);
    if (i.customer_note) msg += `  └ 📝 <i>Note: ${i.customer_note}</i>\n`;
});

msg += `\n💰 <b>TOTALE: €${parseFloat(orderData.total_amount).toFixed(2)}</b>`;

// 4. Link WebApp
const webAppUrl = `${item.urlMiniApp}order-viewer.html?session_id=${orderData.sessionId}&ash=${ash}`;

const payload_owner = {
    chat_id: owner.chat_id,
    text: msg,
    parse_mode: 'HTML',
//    reply_markup: {
//        inline_keyboard: [[{ text: "🧾 Visualizza ed Evadi", web_app: { url: webAppUrl } }]]
//    }
};

return { ...item, payload_owner, ash };

/**
 * n8n Code Node - Get Multitenant Config
 */

const input = items[0].json; 
const rawData = Array.isArray(input) ? input[0] : input;

// 1. Filtro Catalogo (Solo PRO/SER pronti, No SOP)
const categories = rawData.catalog_setup.categories;
let flatCatalog = [];
categories.forEach(cat => {
    if (cat.macrocategories === 'SOP') return; 
    cat.subcategories.forEach(sub => {
        if (sub.blueprint_ready === true) {
            flatCatalog.push({
                callback_data: sub.callback_data,
                name: sub.name,
                short_name: sub.short_name,
                category: cat.name 
            });
        }
    });
});

// 2. Configurazione Budget Multitenant
// Puoi personalizzare queste opzioni in base al Tenant
const budgetOptions = [
    { 
        id: 'LOW', 
        label: 'Essenziale', 
        desc: 'Soluzione focalizzata sulla risoluzione della necessità primaria.' 
    },
    { 
        id: 'MEDIUM', 
        label: 'Completa', 
        desc: 'Copertura totale di ogni aspetto con il miglior bilanciamento valore-prezzo.' 
    },
    { 
        id: 'HIGH', 
        label: 'Prioritaria', 
        desc: 'Massima cura del dettaglio, tempistiche accelerate e standard superiori.' 
    }
];

return {
    success: true,
    catalog: flatCatalog,
    budget_options: budgetOptions // La WebApp ora leggerà questi dati
};

const item = $input.first().json;
const evasion = item.body.evasion_data;
const order = item.order; // Dati recuperati da MongoDB
const owner = item.owner_data;

// Estraiamo il chat_id del cliente
const customerChatId = item.ids.customer_id;

// --- COSTRUZIONE MESSAGGIO RIEPILOGO ---
let msg = `✅ <b>ORDINE CONFERMATO!</b>\n`;
msg += `Il tuo ordine è in preparazione presso <b>${owner.ragione_sociale}</b>\n\n`;

msg += `⏱ <b>TEMPO STIMATO:</b> <code>${evasion.delivery_time} minuti</code>\n`;
msg += `📍 <b>CONSEGNA:</b> <code>${order.address}</code>\n`;
msg += `💳 <b>PAGAMENTO:</b> ${order.payment_mode === 'CARD' ? '💳 Carta (Online)' : '🚚 Contanti alla consegna'}\n\n`;

msg += `🛒 <b>RIEPILOGO PRODOTTI:</b>\n`;

order.items.forEach(i => {
    msg += `• <b>${i.quantity}x ${i.name}</b>\n`;

    // Se ci sono extra
    if (i.selected_extras && i.selected_extras.length > 0) {
        i.selected_extras.forEach(e => {
            msg += `  └ <i>+ ${e.name}</i>\n`;
        });
    }

    // Se c'è una nota per il singolo prodotto
    if (i.customer_note) {
        msg += `  └ 📝 <i>Nota: ${i.customer_note}</i>\n`;
    }
});

msg += `\n💰 <b>TOTALE: €${parseFloat(order.total_amount).toFixed(2)}</b>\n`;
msg += `\n<i>Grazie per il tuo acquisto!</i>`;

// --- PREPARAZIONE PAYLOAD PER IL TUO TELEGRAM MANAGER ---
const payload_owner = {
    chat_id: customerChatId,
    text: msg,
    parse_mode: 'HTML'
};

// Prepariamo l'oggetto aggiornato per MongoDB (mantenendo lo storico)
const updatedOrder = {
    ...order,
    status: evasion.status,
    delivery_time: evasion.delivery_time,
    evaded_at: evasion.timestamp
};

return {
    ...item,
    payload_owner,
    updatedOrder
};
